def test_open_savings_account_valid_mid_range_deposit(<verified_customer_token>, <api_client>):
    payload = {"initial_deposit": 500.00}
    resp = <api_client>.post(
        "/accounts/savings",
        json=payload,
        headers={"Authorization": f"Bearer {<verified_customer_token>}"}
    )
    assert resp.status_code == 201
    body = resp.json()
    assert "account_id" in body
    assert body.get("status") == "active"
    assert body.get("interest_tier") is not None
    <api_client>.delete(
        f"/accounts/{body['account_id']}",
        headers={"Authorization": f"Bearer {<verified_customer_token>}"}
    )

def test_open_savings_account_below_minimum_deposit_returns_422(<verified_customer_token>, <api_client>):
    payload = {"initial_deposit": 50.00}
    resp = <api_client>.post(
        "/accounts/savings",
        json=payload,
        headers={"Authorization": f"Bearer {<verified_customer_token>}"}
    )
    assert resp.status_code == 422
    body = resp.json()
    detail = str(body).lower()
    assert "minimum" in detail or "balance" in detail or "100" in detail

