def test_unverified_customer_cannot_open_savings_account(<unverified_customer_token>, <api_client>):
    payload = {"initial_deposit": 500.00}
    resp = <api_client>.post(
        "/accounts/savings",
        json=payload,
        headers={"Authorization": f"Bearer {<unverified_customer_token>}"}
    )
    assert resp.status_code in (401, 403)
    body = resp.json()
    detail = str(body).lower()
    assert "verif" in detail or "forbidden" in detail or "unauthorized" in detail or "not allowed" in detail
